  "oquefazemos.hero.subtitle.3": { pt: "e desempenho superior para ERPs, CRMs e sistemas empresariais críticos.", en: "and superior performance for ERPs, CRMs and critical enterprise systems.", es: "y rendimiento superior para ERPs, CRMs y sistemas empresariales críticos." },
  "oquefazemos.hero.cta.primary": { pt: "Solicitar Arquitetura Técnica", en: "Request Technical Architecture", es: "Solicitar Arquitectura Técnica" },
