  "oquefazemos.metric.control": { pt: "Controle total da infraestrutura", en: "Full infrastructure control", es: "Control total de la infraestructura" },
  "oquefazemos.metric.sla": { pt: "SLA em minutos", en: "SLA in minutes", es: "SLA en minutos" },
  "oquefazemos.concept.title": { pt: "Não revendemos cloud. Nós construímos.", en: "We don't resell cloud. We build it.", es: "No revendemos cloud. La construimos." },
  "oquefazemos.concept.desc": { pt: "Diferente de provedores que operam sobre grandes nuvens públicas, a MDS Cloud possui infraestrutura própria em data centers Tier III no Brasil. Isso nos permite controlar performance, latência, segurança e custos — sem dependência de terceiros.", en: "Unlike providers that operate on large public clouds, MDS Cloud has its own infrastructure in Tier III data centers in Brazil. This allows us to control performance, latency, security and costs — without third-party dependency.", es: "A diferencia de proveedores que operan sobre grandes nubes públicas, MDS Cloud tiene infraestructura propia en data centers Tier III en Brasil. Esto nos permite controlar rendimiento, latencia, seguridad y costos — sin dependencia de terceros." },
  "oquefazemos.tech.title": { pt: "Diferenciais Técnicos", en: "Technical Differentials", es: "Diferenciales Técnicos" },
  "oquefazemos.tech.1.title": { pt: "Infraestrutura Própria", en: "Own Infrastructure", es: "Infraestructura Propia" },
  "oquefazemos.tech.1.desc": { pt: "Servidores Dell, storages SSD/NVMe e rede de alta capacidade sob gestão total da MDS.", en: "Dell servers, SSD/NVMe storage and high-capacity network under full MDS management.", es: "Servidores Dell, storages SSD/NVMe y red de alta capacidad bajo gestión total de MDS." },
  "oquefazemos.tech.2.title": { pt: "Alta Performance Real", en: "Real High Performance", es: "Alto Rendimiento Real" },
  "oquefazemos.tech.2.desc": { pt: "Ambientes projetados para cargas críticas com baixa latência e alta IOPS.", en: "Environments designed for critical workloads with low latency and high IOPS.", es: "Entornos diseñados para cargas críticas con baja latencia y alta IOPS." },
  "oquefazemos.tech.3.title": { pt: "Escalabilidade Inteligente", en: "Smart Scalability", es: "Escalabilidad Inteligente" },
  "oquefazemos.tech.3.desc": { pt: "Expansão sob demanda com previsibilidade de custo.", en: "On-demand expansion with cost predictability.", es: "Expansión bajo demanda con previsibilidad de costos." },
  "oquefazemos.tech.4.title": { pt: "Operação Especializada", en: "Specialized Operation", es: "Operación Especializada" },
  "oquefazemos.tech.4.desc": { pt: "Infraestrutura integrada ao time de DBAs e suporte técnico 24x7.", en: "Infrastructure integrated with the DBA team and 24x7 technical support.", es: "Infraestructura integrada al equipo de DBAs y soporte técnico 24x7." },
