  "oquefazemos.ideal.5": { pt: "Aplicações industriais", en: "Industrial applications", es: "Aplicaciones industriales" },
  "oquefazemos.stats.clients": { pt: "Clientes ativos", en: "Active clients", es: "Clientes activos" },
