  "contact.hero.subtitle": { pt: "Descubra o suporte especializado em bancos de dados da MDS Cloud.", en: "Discover MDS Cloud's specialized database support.", es: "Descubra el soporte especializado en bases de datos de MDS Cloud." },
  "contact.form.title": { pt: "Nos diga como podemos ajudar a sua empresa!", en: "Tell us how we can help your company!", es: "¡Cuéntenos cómo podemos ayudar a su empresa!" },
