  "contact.form.consent.purpose": { pt: "Compreendo e autorizo o tratamento dos dados para as finalidades informadas, pois tenho conhecimento de que a coleta é necessária para realização dos esclarecimentos solicitados relacionados aos serviços oferecidos.", en: "I understand and authorize the processing of data for the stated purposes, as I am aware that collection is necessary for the clarifications requested regarding the services offered.", es: "Comprendo y autorizo el tratamiento de los datos para las finalidades informadas, ya que tengo conocimiento de que la recolección es necesaria para realizar las aclaraciones solicitadas relacionadas con los servicios ofrecidos." },
  "contact.form.consent.marketing": { pt: "Compreendo e autorizo o tratamento dos dados para fins de recebimento de e-mails com informações relevantes sobre serviços, produtos e/ou notícias diversas sobre compliance, privacidade, segurança da informação e gestão de riscos.", en: "I understand and authorize the processing of data for the purpose of receiving emails with relevant information about services, products and/or various news about compliance, privacy, information security and risk management.", es: "Comprendo y autorizo el tratamiento de los datos para fines de recepción de correos electrónicos con información relevante sobre servicios, productos y/o noticias diversas sobre compliance, privacidad, seguridad de la información y gestión de riesgos." },
  "contact.form.consent.withdraw": { pt: "Você pode retirar seu consentimento a qualquer momento. Para mais informações, consulte nossa", en: "You may withdraw your consent at any time. For more information, please see our", es: "Puede retirar su consentimiento en cualquier momento. Para más información, consulte nuestra" },
