  // About Page
  "about.hero.badge": { pt: "Sobre Nós", en: "About Us", es: "Sobre Nosotros" },
  "about.hero.title": { pt: "Mais do que um provedor de infraestrutura", en: "More than an infrastructure provider", es: "Más que un proveedor de infraestructura" },
  "about.hero.subtitle": { pt: "Somos especialistas em nuvem corporativa brasileira com foco absoluto em sistemas empresariais críticos. Há mais de 16 anos construindo infraestrutura própria de alta performance.", en: "We are specialists in Brazilian corporate cloud with absolute focus on critical enterprise systems. Over 16 years building our own high-performance infrastructure.", es: "Somos especialistas en nube corporativa brasileña con enfoque absoluto en sistemas empresariales críticos. Más de 16 años construyendo infraestructura propia de alto rendimiento." },
  "about.hero.cta.poc": { pt: "Solicitar POC de 30 dias", en: "Request 30-Day POC", es: "Solicitar POC de 30 días" },
  "about.hero.stat.years": { pt: "16+ Anos", en: "16+ Years", es: "16+ Años" },
  "about.hero.stat.clients": { pt: "+1500 Clientes", en: "+1500 Clients", es: "+1500 Clientes" },
  "about.card.storage.hp": { pt: "Storage Alta Performance", en: "High Performance Storage", es: "Almacenamiento Alta Performance" },
  "about.card.servers.tech": { pt: "Servidores Alta Tecnologia", en: "High Technology Servers", es: "Servidores Alta Tecnología" },
  "about.tech.title": { pt: "Tecnologias que utilizamos", en: "Technologies we use", es: "Tecnologías que utilizamos" },
  "about.tech.desc": { pt: "Parceiros tecnológicos e plataformas que garantem a excelência da nossa infraestrutura", en: "Technology partners and platforms that ensure the excellence of our infrastructure", es: "Socios tecnológicos y plataformas que garantizan la excelencia de nuestra infraestructura" },
  "about.whoweare.badge": { pt: "Nossa História", en: "Our History", es: "Nuestra Historia" },
  "about.whoweare.title": { pt: "Quem Somos", en: "Who We Are", es: "Quiénes Somos" },
  "about.whoweare.p1": { pt: "A MDS Cloud é mais do que um provedor de infraestrutura — somos especialistas em nuvem corporativa brasileira com foco absoluto em sistemas empresariais críticos, como ERPs e CRMs, e na gestão de bancos de dados de alta complexidade. Atuamos como parceiros estratégicos de empresas que não toleram falhas, interrupções ou lentidão, porque entendemos que seus sistemas são o coração operacional dos seus negócios.", en: "MDS Cloud is more than an infrastructure provider — we are specialists in Brazilian corporate cloud with absolute focus on critical enterprise systems, such as ERPs and CRMs, and in managing highly complex databases. We act as strategic partners for companies that do not tolerate failures, interruptions or slowdowns, because we understand that their systems are the operational heart of their businesses.", es: "MDS Cloud es más que un proveedor de infraestructura — somos especialistas en nube corporativa brasileña con enfoque absoluto en sistemas empresariales críticos, como ERPs y CRMs, y en la gestión de bases de datos de alta complejidad. Actuamos como socios estratégicos de empresas que no toleran fallas, interrupciones o lentitud, porque entendemos que sus sistemas son el corazón operacional de sus negocios." },
  "about.whoweare.p2": { pt: "Fundada há mais de 16 anos, a MDS Cloud vem construindo, do zero, sua própria infraestrutura em nuvem sob controle total, diferente dos modelos que simplesmente revendem capacidade de grandes nuvens públicas. Essa escolha estratégica nos permite oferecer performance superior, segurança robusta, previsibilidade de custos e suporte humano especializado — tudo com excelência local.", en: "Founded over 16 years ago, MDS Cloud has been building, from scratch, its own cloud infrastructure under full control, unlike models that simply resell capacity from large public clouds. This strategic choice allows us to offer superior performance, robust security, cost predictability and specialized human support — all with local excellence.", es: "Fundada hace más de 16 años, MDS Cloud ha estado construyendo, desde cero, su propia infraestructura en la nube bajo control total, a diferencia de los modelos que simplemente revenden capacidad de grandes nubes públicas. Esta elección estratégica nos permite ofrecer un rendimiento superior, seguridad robusta, previsibilidad de costos y soporte humano especializado — todo con excelencia local." },
  "about.whoweare.p3": { pt: "Somos a nuvem que foi feita para resolver problemas reais de negócios com expertise técnica, proximidade e foco absoluto no cliente.", en: "We are the cloud built to solve real business problems with technical expertise, proximity and absolute focus on the client.", es: "Somos la nube que fue hecha para resolver problemas reales de negocios con experiencia técnica, proximidad y enfoque absoluto en el cliente." },
