  "about.timeline.2024.desc": { pt: "Maior complexo de data centers da América Latina", en: "Largest data center complex in Latin America", es: "Mayor complejo de data centers de América Latina" },
  "about.services.badge": { pt: "Nossos Serviços", en: "Our Services", es: "Nuestros Servicios" },
  "about.services.title": { pt: "O Que Fazemos", en: "What We Do", es: "Lo Que Hacemos" },
  "about.services.subtitle": { pt: "Soluções completas de tecnologia voltadas para o operacional crítico das empresas", en: "Complete technology solutions focused on critical business operations", es: "Soluciones tecnológicas completas orientadas a las operaciones críticas de las empresas" },
  "about.services.cloud.title": { pt: "Nuvem Corporativa de Alta Performance", en: "High Performance Corporate Cloud", es: "Nube Corporativa de Alto Rendimiento" },
  "about.services.cloud.desc": { pt: "Infraestrutura própria, totalmente administrada, com foco em ERPs, CRMs e aplicações empresariais que exigem baixa latência, alta performance e escalabilidade sob demanda — sem surpresas de performance ou dependência de terceiros.", en: "Proprietary, fully managed infrastructure, focused on ERPs, CRMs and enterprise applications that demand low latency, high performance and on-demand scalability — with no performance surprises or third-party dependencies.", es: "Infraestructura propia, totalmente administrada, con foco en ERPs, CRMs y aplicaciones empresariales que exigen baja latencia, alto rendimiento y escalabilidad bajo demanda — sin sorpresas de rendimiento ni dependencia de terceros." },
  "about.services.dba.title": { pt: "Administração de Bancos de Dados (DBA)", en: "Database Administration (DBA)", es: "Administración de Bases de Datos (DBA)" },
  "about.services.dba.desc": { pt: "Serviços avançados de administração, performance, otimização e segurança de bancos de dados. Acompanhamos desde a arquitetura até o tuning contínuo, prevenindo falhas e maximizando eficiência.", en: "Advanced database administration, performance, optimization and security services. We assist from architecture to continuous tuning, preventing failures and maximizing efficiency.", es: "Servicios avanzados de administración, rendimiento, optimización y seguridad de bases de datos. Acompañamos desde la arquitectura hasta el tuning continuo, previniendo fallas y maximizando la eficiencia." },
  "about.services.security.title": { pt: "Segurança e Compliance Integrados", en: "Integrated Security and Compliance", es: "Seguridad y Compliance Integrados" },
  "about.services.security.desc": { pt: "Nossa infraestrutura incorpora políticas de LGPD, backup, criptografia, monitoramento e testes contínuos, com equipe dedicada à proteção e à conformidade regulatória.", en: "Our infrastructure incorporates LGPD policies, backup, encryption, monitoring and continuous testing, with a team dedicated to protection and regulatory compliance.", es: "Nuestra infraestructura incorpora políticas de LGPD, backup, cifrado, monitoreo y pruebas continuas, con equipo dedicado a la protección y la conformidad regulatoria." },
  "about.services.support.title": { pt: "Suporte Técnico Especializado 24×7", en: "Specialized 24×7 Technical Support", es: "Soporte Técnico Especializado 24×7" },
  "about.services.support.desc": { pt: "Equipe humana em tempo integral, com especialistas que conhecem seu ambiente técnico e estão prontos para resolver qualquer necessidade rapidamente — sem intermediários, sem chatbots automáticos.", en: "Full-time human team, with specialists who know your technical environment and are ready to quickly resolve any need — without intermediaries, without automated chatbots.", es: "Equipo humano a tiempo completo, con especialistas que conocen su entorno técnico y están listos para resolver cualquier necesidad rápidamente — sin intermediarios, sin chatbots automáticos." },
  "about.certs.badge": { pt: "Certificações", en: "Certifications", es: "Certificaciones" },
